// PROCESSING archetype: schedule expiry via ISchedulerService
const ttlMs = await this.freedom.getNumber(tenantId, 'verificationTtlMs');
await this.scheduler.scheduleDelayed(
  'expiry-check', ttlMs,
  { tokenId, tenantId },  // no PII in payload
  `expiry:${tokenId}`  // idempotency key for the scheduled job
);
// Surface SLA to client
return { status: 'PENDING', expiresAt, remainingMs: ttlMs };
